import React, { useState } from 'react';
import axios from 'axios';

const TranscriptInput = () => {
  const [file, setFile] = useState(null);
  const [transcript, setTranscript] = useState('');
  const [summary, setSummary] = useState('');
  const [actionItems, setActionItems] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => setFile(e.target.files[0]);

  const handleUpload = async () => {
    if (!file) return;
    setLoading(true);
    const formData = new FormData();
    formData.append('file', file);
    try {
      const res = await axios.post('http://localhost:8000/transcribe', formData);
      setTranscript(res.data.transcript);
      setSummary(res.data.summary?.map((s) => s.summary).join('\n') || 'No summary available');
      setActionItems(res.data.action_items || []);
    } catch (err) {
      console.error('Error uploading:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleClear = () => {
    setFile(null);
    setTranscript('');
    setSummary('');
    setActionItems([]);
  };

  return (
    <div className="bg-gray-900 border border-teal-500 rounded-xl p-6 shadow-lg">
      <h2 className="text-xl font-semibold text-teal-400 mb-4">Upload File</h2>
      <input type="file" onChange={handleFileChange} className="block mb-4 text-gray-300" />
      <div className="flex gap-4 mb-4">
        <button onClick={handleUpload} disabled={loading} className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded">
          {loading ? 'Processing...' : 'Upload & Transcribe'}
        </button>
        <button onClick={handleClear} className="bg-gray-700 hover:bg-gray-600 text-gray-300 px-4 py-2 rounded">
          Clear
        </button>
      </div>

      {summary && (
        <div className="mb-4">
          <h4 className="text-teal-300 mb-2">Summary</h4>
          <p className="whitespace-pre-wrap text-gray-300">{summary}</p>
        </div>
      )}
    </div>
  );
};

export default TranscriptInput;
